INSERT INTO `catatan_guru_wali` (`id_catatan`, `id_siswa`, `id_guru_wali`, `tanggal_catatan`, `kategori_catatan`, `isi_catatan`) VALUES
(1, 645, 4, '2025-10-03', 'Keterampilan', 'afgan sangat tertarik dengan sepak bola, dia banyak cerita tentan pemain sepak bola faforit dia ke saya'),
(2, 632, 12, '2025-10-06', 'Karakter', 'Saat guru meminta tolong sesuatu kepadanya sering sekali untuk membantah atu menolak perintah guru. Kadang kala dia tidak sungkan ganti memerintah gurunya.'),
(3, 714, 10, '2025-10-06', 'Karakter', 'Tya memiliki karakter yang cukup berbeda dengan teman lainnya, cara berbicara kurang sopan dan nada berbicaranya keras dan tinggi. Tetapi tya cukup baik, dia termasuk anak yang ringan tangan'),
(4, 627, 12, '2025-10-06', 'Karakter', 'Anada Alif sangat tertutup terhadap temannya. Kesehariannya dia terlalu pendiam dan pemalu. Namun dia memiliki kelebihan  yaitu rajin dalam menyelesaikan tugas-tugasnya.'),
(5, 699, 10, '2025-10-06', 'Karakter', 'Monica adalah anak yang ringan tangan. Apalagi kalau bapak ibu guru meminta bantuan monica selalu tersenyum dan mengerjakan apa yang di suruh bapak ibu guru'),
(6, 586, 15, '2025-09-15', 'Akademik', 'geo kurang bisa kreatif dan aktif dalam pembelajaran ,lebih banyak bergantung pada temanya'),
(7, 586, 15, '2025-09-15', 'Karakter', 'Geo memmiliki karakter yang kurang tanggungjawab dalam tugas apalagi jika tugas berkelompok ,anak ini lebih banyak pasif daripada aktif dan bisa dikatakan pemalas'),
(8, 570, 19, '2025-09-17', 'Karakter', 'ananda fitrinia memiliki karakter yang ceria, berteman tanpa membeda-bedakan, dan aktif saat pembelajran'),
(9, 590, 15, '2025-10-15', 'Akademik', 'Siswa cukup kreatif dan aktif dalam memberi pertanyaan ke siswa yang presentasi di kelas sehingga kegiatan pembelajaran lebih hidup'),
(10, 587, 15, '2025-08-06', 'Karakter', 'Austin lebih sering berisik saat pembelajaran sehingga guru saat menjelaskan materi akan mengganggu teman-temannya yang konsentrasi mendengarkan guru.'),
(11, 588, 15, '2025-08-18', 'Karakter', 'Mawra lebih memiliki sikap teang saat emnghadapi permasalahan,tidak begitu panik dan ribut di kelas saat pembelajaran'),
(12, 589, 15, '2025-08-25', 'Karakter', 'Ikhzan sangat percaya diri terbukti saat kegiatan sekolah yang harus menampilkan pertunjukan per kelas maka hanya Ikhzan yang berani tampil pantomim bersama Jonathan kelas 7A.'),
(13, 610, 11, '2025-09-03', 'Karakter', 'Alfaro merupakan siswa yang memiliki kepribadian ceria dan aktif di kelas. Namun, ia cenderung sering bersikap usil terhadap teman-temannya, berbicara saat pelajaran berlangsung, dan kadang tampak kurang fokus karena sering mengantuk di kelas. Dengan bimbingan dan arahan yang konsisten, diharapkan Alfaro dapat menyalurkan energinya pada hal-hal yang lebih positif dan meningkatkan kedisiplinannya dalam belajar.'),
(14, 637, 8, '2025-09-15', 'Akademik', '1. Kurang teliti ketika mengerjakan tuga\r\n2. Sering tidak mengerjakan tugas'),
(15, 614, 11, '2025-08-18', 'Komunikasi Ortu', 'Galih Praminto merupakan siswa yang memiliki potensi baik, namun masih kurang memperhatikan dan menyelesaikan tugas yang diberikan guru. Perlu bimbingan dan motivasi agar lebih disiplin dalam mengerjakan tugas.'),
(16, 637, 8, '2025-08-05', 'Karakter', '1. Terlalu aktif dikelas \r\n2. Mudah terpengaruh teman\r\n'),
(17, 637, 8, '2025-10-16', 'Komunikasi Ortu', 'Pernah dilakukan panggilan orang tua untuk mencari solusi tentang anaknya di sekolah'),
(18, 637, 8, '2025-10-16', 'Keterampilan', 'Anaknya kreatif ketika kegiatan keterampilan di sekolah'),
(19, 641, 8, '2025-08-11', 'Akademik', 'Anak yang rajin selalu tepat waktu dalam mengumpulkan tugas'),
(20, 641, 8, '2025-09-11', 'Karakter', 'Sabta anak yang suka menolong dan tanggung jawab dalam melaksanakan piket'),
(21, 608, 15, '2025-12-15', 'Akademik', 'siswa kurang tekun jika menghadapi tugas akademik yang rumit'),
(22, 606, 15, '2025-12-15', 'Lainnya', 'siswa kurang kolaborasi dan komunikasi saat berinteraksi dengan teman lain'),
(23, 585, 15, '2025-12-15', 'Akademik', 'Genta kadang melupakan  tugas yang diberikan oleh guru sehingga nilai kurang maksimal'),
(24, 592, 15, '2025-12-15', 'Lainnya', 'Nadira cukup rajin dalam akademik namun komunikasi dan kolaborasi kurang');
