INSERT INTO `rapor_detail_akademik` (`id_rapor_detail`, `id_rapor`, `id_mapel`, `nilai_akhir`, `nilai_katrol`, `capaian_kompetensi`) VALUES
(1, 26, 1, 73, 78, 'Menunjukkan penguasaan yang baik dalam menyampaikan pendapat sederhana tentang topik familiar dengan alasan.. Perlu penguatan dalam berinteraksi dalam percakapan tentang aktivitas sehari-hari, jadwal sekolah, dan kegiatan waktu luang., melakukan perbandingan sederhana antara dua objek atau situasi., memahami ide utama dan detail relevan dari dialog atau presentasi singkat tentang topik familiar., mempresentasikan hasil recount atau prosedur secara lisan di depan kelas., menanyakan dan memberikan petunjuk arah tempat umum sederhana, menggunakan konjungsi sederhana (contoh: and, but, so) untuk menggabungkan kalimat., menulis paragraf naratif sederhana (recount text) tentang pengalaman pribadi..'),
(5, 27, 3, 84, NULL, 'Menunjukkan penguasaan yang baik dalam mengimplementasikan nilai-nilai Pancasila, menunjukkan contoh pelaksanaan UUD 1945, menjelaskan tata urutan peraturan perundang-undangan, memahami komitmen peraturan perundang-undangan. Perlu penguatan dalam menganalisis kedudukan Pancasila, menjelaskan sejarah singkat UUD 1945.'),
(6, 27, 6, 74, 77, 'Menunjukkan penguasaan yang baik dalam memahami nutrisi dan makan yang baik untuk tubuh, memahami proses pencernaan pada manusia, memahami proses peredaran darah pada manusia, memahami proses ekskresi pada manusia, menerapkan konsep tekanan dalam kehidupan sehari-hari, menghitung besarnya tekanan pada zat padat, cair dan gas, memahami konsep energi dan usaha, mengaplikasikan pesawat sederhana dalam kehidupan sehari-hari.'),
(7, 27, 7, 83, 82, 'Menunjukkan penguasaan yang baik dalam mengevaluasi sumber daya alam, menganalisis kualitas SDM, menganalisis pengaruh proses geografis, menganalisis keragaman aktivitas ekonomi., menjelaskan mobilitas dinamika kependudukan., menganalisis konflik dan integrasi, mengevaluasi perjuangan fisik-pergerakan nasional., menganalisa interaksi bangsa asing.'),
(8, 27, 1, 70, 76, 'Menunjukkan penguasaan yang baik dalam menyampaikan pendapat sederhana tentang topik familiar dengan alasan.. Perlu penguatan dalam berinteraksi dalam percakapan tentang aktivitas sehari-hari, jadwal sekolah, dan kegiatan waktu luang., melakukan perbandingan sederhana antara dua objek atau situasi., memahami ide utama dan detail relevan dari dialog atau presentasi singkat tentang topik familiar., mempresentasikan hasil recount atau prosedur secara lisan di depan kelas., menanyakan dan memberikan petunjuk arah tempat umum sederhana, menggunakan konjungsi sederhana (contoh: and, but, so) untuk menggabungkan kalimat., menulis paragraf naratif sederhana (recount text) tentang pengalaman pribadi..'),
(9, 27, 9, 78, 92, 'Menunjukkan penguasaan yang baik dalam membandingkan teknik dan prosedur, mengidentifikasi inovasi modifikasi  produk, menganalisis karakteristik produk kerajinan, merancang desain produk kerajinan, mengembangkan  alternatif desain produk.'),
(10, 28, 3, 76, NULL, 'Menunjukkan penguasaan yang baik dalam menjelaskan sejarah singkat UUD 1945, menjelaskan tata urutan peraturan perundang-undangan. Perlu penguatan dalam menganalisis kedudukan Pancasila, mengimplementasikan nilai-nilai Pancasila, menunjukkan contoh pelaksanaan UUD 1945, memahami komitmen peraturan perundang-undangan.'),
