INSERT INTO `rapor_detail_akademik` (`id_rapor_detail`, `id_rapor`, `id_mapel`, `nilai_akhir`, `nilai_katrol`, `capaian_kompetensi`) VALUES
(112, 48, 1, 83, 85, 'Menunjukkan penguasaan yang baik dalam mempresentasikan informasi atau argumen secara jelas dan menarik, menyesuaikan dengan tujuan dan audiens, menemukan dan mengevaluasi informasi spesifik dalam teks deskriptif dan prosedur., menganalisis struktur dan ciri kebahasaan dari berbagai jenis teks., mengevaluasi ide utama dan informasi pendukung dalam teks, mengidentifikasi sudut pandang atau bias dalam teks., mengidentifikasi urutan kejadian dalam teks prosedur sederhana, menyusun teks prosedur sederhana dengan langkah-langkah yang jelas., merencanakan, menulis, dan merevisi paragraf yang lebih kompleks untuk tujuan informatif, imajinatif, atau persuasif.. Perlu penguatan dalam melakukan inferensi untuk memahami makna yang lebih dalam, tujuan penulis, dan informasi yang tidak tersurat., menghasilkan teks multi-paragraf yang koheren dan kohesif (contoh: esai sederhana, surat persuasif)..'),
(113, 48, 9, 82, 94, 'Menunjukkan penguasaan yang baik dalam menyusun proposal desain produk, merancang desain produk inovatif, membuat produk kerajinan kompleks, merumuskan ide-ide inovatif produk, menganalisis karakteristik produk kerajinan, mengidentifikasi memecahkan masalah potensial, mendokumentasikan proses pembuatan produk, mengeksplorasi mengidentifikasi tren  produk.'),
(114, 1, 2, 52, 75, 'Menunjukkan penguasaan yang sangat baik dalam tata cara dan fungsi sujud, meneladani sikap Asmaul Husna. Namun, perlu penguatan lebih lanjut dalam menerapkan perilaku ikhlas, perkembangan Dinasti Bani Umayyah..'),
(115, 1, 3, 69, 82, 'Menunjukkan penguasaan yang sangat baik dalam mendeskripsikan perumusan Pancasila, mendeskripsikan kelahiran Pancasila. Namun, perlu penguatan lebih lanjut dalam makna sila-sila Pancasila dan penerapannya, menerapkan norma dalam kehidupan masyarakat.'),
(116, 1, 6, 70, 80, 'Menunjukkan penguasaan yang sangat baik dalam wujud zat dan perubahan fisika maupun kimia, menghitung kerapatan zat. Namun, perlu penguatan lebih lanjut dalam melakukan pengukuran terhadap besaran pokok maupun besaran turunan, merancang percobaan dengan melaporkannya dalam bentuk metode ilmiah.'),
(117, 1, 7, 52, 77, 'Menunjukkan penguasaan yang sangat baik dalam kegiatan ekonomi, kehidupan masa Praaksara.. Namun, perlu penguatan lebih lanjut dalam menganalisa konektivitas antarruang., mendeskripsikan kondisi lingkungan.'),
(118, 1, 1, 81, 76, 'Menunjukkan penguasaan yang sangat baik dalam instruksi lisan sederhana yang terkait dengan aktivitas sehari-hari di kelas., menulis paragraf deskriptif tentang tempat atau peristiwa yang dikenal.. Namun, perlu penguatan lebih lanjut dalam menyapa dan berpamitan dalam situasi formal dan informal sederhana, mempresentasikan informasi dasar tentang diri atau rutinitas harian dalam format lisan singkat..'),
(119, 1, 9, 71, 90, 'Menunjukkan penguasaan yang sangat baik dalam membuat sketsa desain produk, merencanakan langkah pembuatan produk. Semua tujuan pembelajaran telah tercapai dengan baik.'),
