(4, 1, 4, 'D', 'BIG-71-01', 'Memperkenalkan diri dan orang lain dengan informasi dasar secara lisan.', 1, 1),
(5, 1, 4, 'D', 'BIG-71-02', 'Menyapa dan berpamitan dalam situasi formal dan informal sederhana', 1, 1),
